"use client";

import { useState } from "react";

// shadcn
import { Alert, AlertAction } from "@/components/ui/alert";
import { Button } from "@/components/ui/button";

// assets
import { ShieldAlert, X } from "lucide-react";

//  ------------------------------ | ALERT - DISMISSIBLE DANGER | ------------------------------  //

export default function AlertDismissibleDanger() {
  const [isVisible, setIsVisible] = useState(true);

  if (!isVisible) return null;

  return (
    <Alert className="rounded-lg border grid-cols-1 flex items-center gap-3 border-red-500/20 bg-red-500/10 text-red-500 relative pr-10">
      <ShieldAlert className="h-5 w-5 shrink-0" />
      <span>
        <strong>Error!</strong> Something went wrong while processing your
        request.
      </span>
      <AlertAction className="absolute right-2 top-2">
        <Button
          size="icon"
          onClick={() => setIsVisible(false)}
          className="text-lg flex items-center justify-center rounded w-7 h-7 text-inherit bg-transparent hover:bg-black/5 dark:hover:bg-white/5"
        >
          <X className="h-4 w-4" />
        </Button>
      </AlertAction>
    </Alert>
  );
}
